return [
  { json: { label: 'Web app',   url: 'https://www.stpetemusic.live/api/health',      acceptAny: false } },
  { json: { label: 'Admin app', url: 'https://admin.stpetemusic.live/api/health',    acceptAny: false } },
  { json: { label: 'n8n',       url: 'https://n8n.stpetemusic.live/healthz',         acceptAny: false } },
  { json: { label: 'Listmonk',  url: 'https://listmonk.stpetemusic.live/api/health', acceptAny: false } },
  { json: { label: 'HLS CDN',   url: 'https://hls.stpetemusic.live',                  acceptAny: true  } }
];

const pings = $input.all();
const endpoints = $('Define Endpoints').all();

const failures = pings.map((ping, i) => {
  const endpoint = endpoints[i].json;
  const statusCode = ping.json.statusCode || 0;
  const ok = endpoint.acceptAny ? statusCode > 0 : (statusCode >= 200 && statusCode < 400);
  return { label: endpoint.label, ok, statusCode };
}).filter(r => !r.ok);

if (failures.length === 0) return [];

// Rate limit: only alert once per hour per failing service
const workflowData = $getWorkflowStaticData('global');
const now = Date.now();
const DEBOUNCE_MS = 60 * 60 * 1000;

const newFailures = failures.filter(f => {
  const lastAlert = workflowData[`lastAlert_${f.label}`] || 0;
  return now - lastAlert > DEBOUNCE_MS;
});

newFailures.forEach(f => {
  workflowData[`lastAlert_${f.label}`] = now;
});

if (newFailures.length === 0) return [];

const names = newFailures.map(f => f.label).join(', ');
const lines = newFailures
  .map(f => `${f.label} \u2014 ${f.statusCode > 0 ? 'HTTP ' + f.statusCode : 'TIMEOUT'}`)
  .join('\n');

return [{ json: {
  subject: `\uD83D\uDEA8 StPeteMusic: ${names}`,
  text: `${lines}\n\n\u2192 https://admin.stpetemusic.live`
} }];
